import React, { useEffect, useState } from "react";
import axios from "axios";
import { Bar, Pie } from "react-chartjs-2";
import './AdminDashboard.css';

import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  ArcElement,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(CategoryScale, LinearScale, BarElement, ArcElement, Tooltip, Legend);

const AdminDashboard = () => {
  const [predictions, setPredictions] = useState([]);

  // Fetch data initially and every 10 seconds
  useEffect(() => {
    const fetchData = async () => {
      try {
        const res = await axios.get("http://localhost:5000/admin/dashboard");
        setPredictions(res.data.predictions);
      } catch (err) {
        console.error("Error fetching data:", err);
      }
    };

    fetchData();
    const interval = setInterval(fetchData, 10000); // refresh every 10s
    return () => clearInterval(interval);
  }, []);

  // Calculate stats dynamically
  const totalUsers = predictions.length;
  const salaries = predictions.map(p => p.salary);
  const avgSalary = salaries.length ? (salaries.reduce((a, b) => a + b, 0) / salaries.length) : 0;
  const highestSalary = salaries.length ? Math.max(...salaries) : 0;
  const lowestSalary = salaries.length ? Math.min(...salaries) : 0;

  // Bar Chart: Salary Distribution
  const barData = {
    labels: ["<40k", "40-60k", "60-80k", "80-100k", ">100k"],
    datasets: [{
      label: "Predictions",
      data: [
        predictions.filter(p => p.salary < 40000).length,
        predictions.filter(p => p.salary >= 40000 && p.salary < 60000).length,
        predictions.filter(p => p.salary >= 60000 && p.salary < 80000).length,
        predictions.filter(p => p.salary >= 80000 && p.salary < 100000).length,
        predictions.filter(p => p.salary >= 100000).length,
      ],
      backgroundColor: ["#36A2EB","#6A5ACD","#FFA07A","#9370DB","#1E90FF"]
    }]
  };

  // Pie Chart: Experience Level
  const pieData = {
    labels: ["Entry", "Intermediate", "Experienced", "Post-Graduate"],
    datasets: [{
      data: [
        predictions.filter(p => p.experience === "Entry").length,
        predictions.filter(p => p.experience === "Intermediate").length,
        predictions.filter(p => p.experience === "Experienced").length,
        predictions.filter(p => p.experience === "Post-Graduate").length
      ],
      backgroundColor: ["#4e73df","#f6c23e","#1cc88a","#e74a3b"]
    }]
  };

  return (
    <div className="dashboard-container">
      {/* Sidebar */}
      <div className="sidebar">
        <h2>Admin</h2>
        <ul>
          <li>Dashboard</li>
          <li>Manage Users</li>
          <li>Reports</li>
          <li>Settings</li>
        </ul>
      </div>

      {/* Main Content */}
      <div className="main-content">
        <div className="navbar"><h1>Admin Dashboard</h1></div>

        {/* Cards */}
        <div className="cards">
          <div className="card card1"><p>Avg Salary</p><h2>₹{avgSalary.toFixed(0)}</h2></div>
          <div className="card card2"><p>Highest Salary</p><h2>₹{highestSalary}</h2></div>
          <div className="card card3"><p>Lowest Salary</p><h2>₹{lowestSalary}</h2></div>
          <div className="card card4"><p>Total Users</p><h2>{totalUsers}</h2></div>
        </div>

        {/* Charts */}
        <div className="charts">
          <div className="chart"><h3>Salary Distribution</h3><Bar data={barData} /></div>
          <div className="chart"><h3>Experience Level</h3><Pie data={pieData} /></div>
        </div>

        {/* Table */}
        <div className="table-section">
          <h3>Recent Predictions</h3>
          <table>
            <thead>
              <tr><th>Email</th><th>Role</th><th>Location</th><th>Salary</th></tr>
            </thead>
            <tbody>
              {predictions.slice(-10).reverse().map((p, idx) => (
                <tr key={idx}>
                  <td>{p.email}</td>
                  <td>{p.role}</td>
                  <td>{p.location}</td>
                  <td>₹{p.salary}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
